/**
 * Simple in-process event bus for publish/subscribe communication.
 *
 * Used by the notification system to dispatch notification events
 * to channel handlers (email, SMS, etc.) without tight coupling.
 *
 * Distinct from src/events/event-bus.ts which handles typed application
 * domain events — this is a lightweight, general-purpose pub/sub bus.
 */

export type EventHandler<T = unknown> = (data: T) => void | Promise<void>;

export class SimpleEventBus {
  private handlers = new Map<string, EventHandler[]>();

  /**
   * Subscribe to an event by name. Returns an unsubscribe function.
   */
  subscribe(event: string, handler: EventHandler): () => void {
    const list = this.handlers.get(event) ?? [];
    list.push(handler);
    this.handlers.set(event, list);

    return () => {
      const current = this.handlers.get(event) ?? [];
      const idx = current.indexOf(handler);
      if (idx >= 0) {
        current.splice(idx, 1);
      }
    };
  }

  /**
   * Publish an event to all subscribers. Handlers run sequentially.
   */
  async publish(event: string, data: unknown): Promise<void> {
    const handlers = this.handlers.get(event) ?? [];
    for (const handler of handlers) {
      await handler(data);
    }
  }

  /**
   * Remove all subscribers.
   */
  clear(): void {
    this.handlers.clear();
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Uses an internal EventBus to dispatch notification events to channel handlers.
 * Channel handlers (e.g., EmailNotificationChannel) subscribe to the notification
 * bus and deliver messages through their respective transports.
 *
 * NOTE: This service currently uses TWO different patterns for receiving
 * notifications, which is inconsistent and should be unified:
 *
 * 1. EventBus subscriptions (event-driven) — used for order:created events
 * 2. CallbackRegistry (direct callbacks) — used for order:status-changed events
 *
 * Both approaches work but the mixed usage makes the codebase harder to
 * maintain. A future refactor should pick ONE approach and use it consistently.
 *
 * Depends on:
 * - EventBus (event system) for receiving some events
 * - CallbackRegistry (direct callbacks) for other events
 * - SimpleEventBus (notification dispatch) for channel-based delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { SimpleEventBus } from '../utils/event-bus.js';
import { Logger } from '../utils/logger.js';

/**
 * Event payload dispatched to notification channels via the internal bus.
 */
export interface NotificationEvent {
  type: string;
  recipient: string;
  subject: string;
  body: string;
}

/**
 * Interface for notification delivery channels.
 * Implement this to add new delivery methods (email, SMS, push, etc.).
 */
export interface NotificationChannel {
  handle(event: NotificationEvent): void | Promise<void>;
}

/**
 * Email notification channel — delivers notifications via email.
 * Stores delivered emails in-memory for testability.
 */
export class EmailNotificationChannel implements NotificationChannel {
  private deliveredEmails: NotificationEvent[] = [];
  private logger = new Logger('EmailChannel');

  handle(event: NotificationEvent): void {
    this.logger.info(`Sending email to ${event.recipient}: ${event.subject}`);
    this.deliveredEmails.push({ ...event });
  }

  getDeliveredEmails(): NotificationEvent[] {
    return [...this.deliveredEmails];
  }

  clearDeliveredEmails(): void {
    this.deliveredEmails = [];
  }
}

export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private notificationBus = new SimpleEventBus();

  constructor(
    private eventBus: EventBus,
    channels: NotificationChannel[] = [],
  ) {
    this.registerHandlers();
    this.registerChannels(channels);
  }

  /**
   * Register notification channels on the internal bus.
   */
  private registerChannels(channels: NotificationChannel[]): void {
    for (const channel of channels) {
      this.notificationBus.subscribe('notification', (data) => {
        return channel.handle(data as NotificationEvent);
      });
    }
  }

  /**
   * Register event handlers for notification triggers.
   *
   * Uses EventBus for order creation (event-driven pattern)
   * and CallbackRegistry for status changes (direct callback pattern).
   */
  private registerHandlers(): void {
    // Pattern 1: EventBus subscription for order creation
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    // Pattern 2: CallbackRegistry for status changes
    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.sendNotification({
      type: 'order:confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.sendNotification({
      type: 'order:status-update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  /**
   * Send a notification: store in-memory and dispatch to channels via the notification bus.
   */
  private sendNotification(params: {
    type: string;
    recipient: string;
    subject: string;
    body: string;
  }): void {
    const notification: Notification = {
      id: generateNotificationId(),
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      sentAt: new Date(),
    };
    this.notifications.push(notification);
    this.logger.info(`Notification sent: ${notification.id} to ${params.recipient}`);

    // Dispatch to registered channels
    const event: NotificationEvent = {
      type: params.type,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
    };
    void this.notificationBus.publish('notification', event);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

