import { describe, it, expect, beforeEach } from 'vitest';
import { SimpleEventBus } from '../../src/utils/event-bus.js';

describe('SimpleEventBus', () => {
  let bus: SimpleEventBus;

  beforeEach(() => {
    bus = new SimpleEventBus();
  });

  it('should deliver published data to subscribers', async () => {
    const received: unknown[] = [];
    bus.subscribe('test', (data) => {
      received.push(data);
    });

    await bus.publish('test', { message: 'hello' });

    expect(received).toHaveLength(1);
    expect(received[0]).toEqual({ message: 'hello' });
  });

  it('should support multiple subscribers for the same event', async () => {
    const received: string[] = [];
    bus.subscribe('test', () => {
      received.push('handler-1');
    });
    bus.subscribe('test', () => {
      received.push('handler-2');
    });

    await bus.publish('test', null);

    expect(received).toEqual(['handler-1', 'handler-2']);
  });

  it('should not deliver events to unrelated subscribers', async () => {
    const received: unknown[] = [];
    bus.subscribe('other', (data) => {
      received.push(data);
    });

    await bus.publish('test', 'data');

    expect(received).toHaveLength(0);
  });

  it('should unsubscribe when calling the returned function', async () => {
    const received: unknown[] = [];
    const unsubscribe = bus.subscribe('test', (data) => {
      received.push(data);
    });

    await bus.publish('test', 'first');
    unsubscribe();
    await bus.publish('test', 'second');

    expect(received).toEqual(['first']);
  });

  it('should clear all subscribers', async () => {
    const received: unknown[] = [];
    bus.subscribe('a', (data) => {
      received.push(data);
    });
    bus.subscribe('b', (data) => {
      received.push(data);
    });

    bus.clear();
    await bus.publish('a', 1);
    await bus.publish('b', 2);

    expect(received).toHaveLength(0);
  });

  it('should handle async handlers sequentially', async () => {
    const order: number[] = [];
    bus.subscribe('test', async () => {
      await new Promise((resolve) => setTimeout(resolve, 10));
      order.push(1);
    });
    bus.subscribe('test', () => {
      order.push(2);
    });

    await bus.publish('test', null);

    expect(order).toEqual([1, 2]);
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  EmailNotificationChannel,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { NotificationEvent } from '../../src/services/notification.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('Email Notification Channel', () => {
  let eventBus: EventBus;
  let emailChannel: EmailNotificationChannel;
  let service: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    emailChannel = new EmailNotificationChannel();
    service = new NotificationService(eventBus, [emailChannel]);
    resetNotificationIdCounter();
  });

  it('should deliver order confirmation emails via the email channel', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        ],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const emails = emailChannel.getDeliveredEmails();
    expect(emails).toHaveLength(1);
    expect(emails[0]?.type).toBe('order:confirmation');
    expect(emails[0]?.recipient).toBe('alice@example.com');
    expect(emails[0]?.subject).toContain('Order Confirmation');
    expect(emails[0]?.body).toContain('Widget x2');
    expect(emails[0]?.body).toContain('$20.00');
  });

  it('should deliver status update emails via the email channel', () => {
    const event: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    statusChangeCallbacks.notify(event);

    const emails = emailChannel.getDeliveredEmails();
    expect(emails).toHaveLength(1);
    expect(emails[0]?.type).toBe('order:status-update');
    expect(emails[0]?.recipient).toBe('user-1');
    expect(emails[0]?.subject).toContain('Order Update');
    expect(emails[0]?.body).toContain('pending');
    expect(emails[0]?.body).toContain('confirmed');
  });

  it('should support multiple channels simultaneously', async () => {
    const secondChannel = new EmailNotificationChannel();
    const multiService = new NotificationService(eventBus, [emailChannel, secondChannel]);

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Gadget', quantity: 1, unitPrice: 50 },
        ],
        total: 50,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Bob',
        email: 'bob@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailChannel.getDeliveredEmails()).toHaveLength(1);
    expect(secondChannel.getDeliveredEmails()).toHaveLength(1);

    // Suppress unused variable warning
    void multiService;
  });

  it('should work with custom NotificationChannel implementations', async () => {
    const captured: NotificationEvent[] = [];
    const customChannel = {
      handle(event: NotificationEvent) {
        captured.push(event);
      },
    };

    const customService = new NotificationService(eventBus, [customChannel]);

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Item', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Carol',
        email: 'carol@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(captured).toHaveLength(1);
    expect(captured[0]?.recipient).toBe('carol@example.com');

    void customService;
  });

  it('should clear delivered emails', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);
    expect(emailChannel.getDeliveredEmails()).toHaveLength(1);

    emailChannel.clearDeliveredEmails();
    expect(emailChannel.getDeliveredEmails()).toHaveLength(0);
  });
});

