+import { describe, it, expect, beforeEach } from 'vitest';
+import { SimpleEventBus } from '../../src/utils/event-bus.js';
+
+describe('SimpleEventBus', () => {
+  let bus: SimpleEventBus;
+
+  beforeEach(() => {
+    bus = new SimpleEventBus();
+  });
+
+  it('should deliver published data to subscribers', async () => {
+    const received: unknown[] = [];
+    bus.subscribe('test', (data) => {
+      received.push(data);
+    });
+
+    await bus.publish('test', { message: 'hello' });
+
+    expect(received).toHaveLength(1);
+    expect(received[0]).toEqual({ message: 'hello' });
+  });
+
+  it('should support multiple subscribers for the same event', async () => {
+    const received: string[] = [];
+    bus.subscribe('test', () => {
+      received.push('handler-1');
+    });
+    bus.subscribe('test', () => {
+      received.push('handler-2');
+    });
+
+    await bus.publish('test', null);
+
+    expect(received).toEqual(['handler-1', 'handler-2']);
+  });
+
+  it('should not deliver events to unrelated subscribers', async () => {
+    const received: unknown[] = [];
+    bus.subscribe('other', (data) => {
+      received.push(data);
+    });
+
+    await bus.publish('test', 'data');
+
+    expect(received).toHaveLength(0);
+  });
+
+  it('should unsubscribe when calling the returned function', async () => {
+    const received: unknown[] = [];
+    const unsubscribe = bus.subscribe('test', (data) => {
+      received.push(data);
+    });
+
+    await bus.publish('test', 'first');
+    unsubscribe();
+    await bus.publish('test', 'second');
+
+    expect(received).toEqual(['first']);
+  });
+
+  it('should clear all subscribers', async () => {
+    const received: unknown[] = [];
+    bus.subscribe('a', (data) => {
+      received.push(data);
+    });
+    bus.subscribe('b', (data) => {
+      received.push(data);
+    });
+
+    bus.clear();
+    await bus.publish('a', 1);
+    await bus.publish('b', 2);
+
+    expect(received).toHaveLength(0);
+  });
+
+  it('should handle async handlers sequentially', async () => {
+    const order: number[] = [];
+    bus.subscribe('test', async () => {
+      await new Promise((resolve) => setTimeout(resolve, 10));
+      order.push(1);
+    });
+    bus.subscribe('test', () => {
+      order.push(2);
+    });
+
+    await bus.publish('test', null);
+
+    expect(order).toEqual([1, 2]);
+  });
+});
